// Example: use-cases.ts
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import apiClient from '@/lib/api-client'

interface Case {
  id: string
  title: string
  legalType: string
  status: string
  // ... other fields
}

export function useCases(filters?: any) {
  return useQuery({
    queryKey: ['cases', filters],
    queryFn: async () => {
      const { data } = await apiClient.get<Case[]>('/api/v1/cases', { params: filters })
      return data
    },
    staleTime: 30000, // 30 seconds
  })
}

export function useCase(id: string) {
  return useQuery({
    queryKey: ['cases', id],
    queryFn: async () => {
      const { data } = await apiClient.get<Case>(`/api/v1/cases/${id}`)
      return data
    },
    enabled: !!id,
  })
}

export function useCreateCase() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (newCase: Partial<Case>) => {
      const { data } = await apiClient.post<Case>('/api/v1/cases', newCase)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['cases'] })
    },
  })
}

export function useUpdateCase() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async ({ id, updates }: { id: string; updates: Partial<Case> }) => {
      const { data } = await apiClient.patch<Case>(`/api/v1/cases/${id}`, updates)
      return data
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['cases'] })
      queryClient.invalidateQueries({ queryKey: ['cases', data.id] })
    },
  })
}

